const b = $json.body || {};
// Key on DIGITS ONLY (no '+'); this is the in-memory session key. The main funnel re-heals to E.164.
const phone = (b.From || b.from || '').toString().replace('whatsapp:', '').replace(/\D/g, '');
const text = (b.Body || b.body || '').toString().trim();
const name = (b.ProfileName || b.profileName || '').toString().trim();
// Twilio's per-message id — used to dedupe its retry-on-slow-response (avoids a divergent 2nd reply).
const sid = (b.MessageSid || b.SmsMessageSid || b.SmsSid || '').toString().trim();
return [{ json: { phone: phone, text: text, name: name, sid: sid } }];

const inb = $('Code: Parse Inbound').item.json;
const key = String(inb.phone || '').replace(/\D/g, '');
// Live conversation state lives IN MEMORY (workflow static data), keyed by phone digits.
// Read key === write key, so there are no duplicate rows and no Google-Sheets type coercion.
const store = $getWorkflowStaticData('global');
store.sessions = store.sessions || {};
const sess = store.sessions[key] || null;

// Idempotency: Twilio retries the same inbound (same MessageSid) when we answer slowly.
// If we already handled this exact message, replay the SAME reply instead of re-processing
// it into a divergent second message.
if (sess && inb.sid && sess.lastSid && sess.lastSid === inb.sid) {
  return [{ json: { phone: key, mode: 'dedup', dedup_twiml: sess.lastTwiml || '<Response></Response>' } }];
}

const stage = sess ? String(sess.stage || 'collecting') : 'new';
const name = (sess && sess.name) || inb.name || '';
const email = (sess && sess.email) || '';
const offered = (sess && Array.isArray(sess.offered)) ? sess.offered : [];

let mode = 'qualify', accumulated = '', chosen_slot = '', reprompt = '';
if (stage === 'awaiting_slot') {
  accumulated = (sess && sess.case) || '';
  const m = (inb.text || '').match(/\d+/);
  const idx = m ? parseInt(m[0], 10) : NaN;
  if (!isNaN(idx) && idx >= 1 && idx <= offered.length) {
    mode = 'book';
    chosen_slot = offered[idx - 1].iso;
  } else {
    mode = 'reprompt';
    reprompt = "Please reply with the number of your preferred time (e.g. 2).";
  }
} else {
  mode = 'qualify';
  accumulated = (((sess && sess.case) ? sess.case + ' ' : '') + (inb.text || '')).trim();
}

return [{ json: { phone: key, name: name, email: email, sid: inb.sid || '', stage: stage, mode: mode, accumulated: accumulated, chosen_slot: chosen_slot, reprompt: reprompt, offered: JSON.stringify(offered) } }];

const d = $('Code: Decide').item.json;
const mode = d.mode;

// Twilio retry of an already-handled message: echo the exact prior reply, change nothing.
if (mode === 'dedup') {
  return [{ json: { twiml: d.dedup_twiml || '<Response></Response>' } }];
}

const r = (mode === 'reprompt') ? {} : ($json || {});
let reply = '', stage = d.stage || 'collecting', offered = [];
try { offered = d.offered ? JSON.parse(d.offered) : []; } catch (e) { offered = []; }

if (mode === 'reprompt') {
  reply = d.reprompt || "Please reply with the number of your preferred time (e.g. 2).";
  stage = 'awaiting_slot';
} else if (mode === 'book') {
  if (r.booked === true) {
    reply = "Booked! Your free consult is set for " + (r.consult_slot || 'your selected time') + ". See you then!";
    stage = 'done';
    offered = [];
  } else {
    offered = offered.filter(s => s.iso !== d.chosen_slot);
    if (offered.length) {
      const lines = offered.map((s, i) => (i + 1) + ') ' + s.label).join('\n');
      reply = "Sorry — that time was just taken. Other openings:\n" + lines + "\nReply 1, 2, or 3.";
      stage = 'awaiting_slot';
    } else {
      reply = "Sorry — that time was just taken. Reply with anything and I'll pull fresh times.";
      stage = 'collecting';
    }
  }
} else { // qualify
  const verdict = r.verdict || (r.qualified === true ? 'qualified' : 'needs_info');
  if (verdict === 'qualified') {
    offered = (r.slots || []).slice(0, 3);
    if (offered.length) {
      const lines = offered.map((s, i) => (i + 1) + ') ' + s.label).join('\n');
      reply = "Good news — you look like a fit! Open consult times:\n" + lines + "\nReply 1, 2, or 3 to book.";
      stage = 'awaiting_slot';
    } else {
      reply = r.sms_reply || "Good news — you're a fit! Our team will reach out with available times.";
      stage = 'done';
    }
  } else if (verdict === 'declined') {
    reply = r.sms_reply || "Thanks for reaching out — this isn't something our team can take on.";
    stage = 'done';
  } else {
    reply = r.sms_reply || "Could you tell us a bit more about what happened?";
    stage = 'collecting';
  }
}
const esc = (t) => String(t).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const twiml = "<Response><Message>" + esc(reply) + "</Message></Response>";

// Persist the updated session in memory (workflow static data). Same key we read with — no
// duplicate rows, no Sheets coercion, no per-turn Sheets round-trip. lastSid/lastTwiml power dedup.
const store = $getWorkflowStaticData('global');
store.sessions = store.sessions || {};
store.sessions[d.phone] = {
  name: d.name, email: d.email, case: d.accumulated, stage: stage,
  offered: offered, lastSid: d.sid || '', lastTwiml: twiml,
  updatedAt: new Date().toISOString()
};

return [{ json: { twiml: twiml } }];
